export function markdownFilename(title: string): string {
  const visible = title.toLowerCase().replace(/[^\p{L}\p{N}]+/gu, "-").replace(/^-+|-+$/g, "");
  return `${visible === "" ? "untitled" : visible}.md`;
}

export function slackTitle(messages: readonly SlackMessage[], timeZone: string): string {
  const timestamp = Number(messages[0]!.ts) * 1000;
  const parts = new Intl.DateTimeFormat("en-CA", { timeZone, year: "numeric", month: "2-digit", day: "2-digit" }).formatToParts(timestamp);
  const date = `${parts.find((part) => part.type === "year")!.value}-${parts.find((part) => part.type === "month")!.value}-${parts.find((part) => part.type === "day")!.value}`;
  const preview = messages[0]!.text
    .replace(/https?:\/\/\S+/g, "")
    .slice(0, 30)
    .replace(/[^\p{L}\p{N}_\s-]/gu, "")
    .replace(/[\s-]+/g, "_")
    .replace(/^_+|_+$/g, "");
  return `${date}-${preview}`;
}

