function decodeHtmlEntities(value: string): string {
  return value.replace(/&(#[0-9]+;?|#[xX][0-9a-fA-F]+;?|[^\t\n\f <&#;]{1,32};?)/g, (match, entity: string) => {
    if (entity[0] === "#") {
      const hexadecimal = entity[1] === "x" || entity[1] === "X";
      const codePoint = Number.parseInt(entity.slice(hexadecimal ? 2 : 1).replace(/;$/, ""), hexadecimal ? 16 : 10);
      const invalid = new Map<number, string>([[0, "�"], [13, "\r"], [128, "€"], [129, "\u0081"], [130, "‚"], [131, "ƒ"], [132, "„"], [133, "…"], [134, "†"], [135, "‡"], [136, "ˆ"], [137, "‰"], [138, "Š"], [139, "‹"], [140, "Œ"], [141, "\u008d"], [142, "Ž"], [143, "\u008f"], [144, "\u0090"], [145, "‘"], [146, "’"], [147, "“"], [148, "”"], [149, "•"], [150, "–"], [151, "—"], [152, "˜"], [153, "™"], [154, "š"], [155, "›"], [156, "œ"], [157, "\u009d"], [158, "ž"], [159, "Ÿ"]]);
      if (invalid.has(codePoint)) return invalid.get(codePoint)!;
      if (codePoint >= 0xd800 && codePoint <= 0xdfff || codePoint > 0x10ffff) return "�";
      if (codePoint >= 1 && codePoint <= 8 || codePoint === 11 || codePoint >= 14 && codePoint <= 31 || codePoint >= 127 && codePoint <= 159 || codePoint >= 64976 && codePoint <= 65007 || (codePoint & 0xffff) === 0xffff || (codePoint & 0xffff) === 0xfffe) return "";
      return String.fromCodePoint(codePoint);
    }
    if (htmlEntities[entity] !== undefined) return htmlEntities[entity];
    for (let length = entity.length - 1; length > 1; length -= 1) {
      const prefix = entity.slice(0, length);
      if (htmlEntities[prefix] !== undefined) return `${htmlEntities[prefix]}${entity.slice(length)}`;
    }
    return match;
  });
}

function decodeBase64Url(value: string): string {
  if (value.length % 4 !== 0) {
    throw new Error("Incorrect padding");
  }
  return Buffer.from(value, "base64url").toString("utf8");
}

export function slackText(text: string, userCache: Readonly<Record<string, string>>): string {
  return decodeHtmlEntities(
    text
      .replace(/<@([A-Z0-9]+)(?:\|[^>]+)?>/g, (_, userId: string) => `@${userCache[userId]!.slice(0)}`)
      .replace(/<#[A-Z0-9]+\|([^>]+)>/g, "#$1")
      .replace(/<#([A-Z0-9]+)>/g, "#$1")
      .replace(/<!subteam\^[A-Z0-9]+\|([^>]+)>/g, "$1")
      .replace(/<!(here|channel|everyone)>/g, "@$1")
      .replace(/<(https?:\/\/[^|>\s]+)\|([^>]+)>/g, "[$2]($1)")
      .replace(/<(https?:\/\/[^>]+)>/g, "$1")
      .replace(/<(mailto:[^|>]+)\|([^>]+)>/g, "$2")
      .replace(/```([^\n])/g, "```\n$1")
      .replace(/([^\n])```/g, "$1\n```"),
  );
}

